import{_ as b,o as e,c as a,j as r,a as d,a1 as t}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"宝石人","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/宝石人.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/宝石人.md"}'),n={name:"4.资源分区/1.血统与训练/6.一次性血统/宝石人.md"};function s(o,p,l,_,i,c){return e(),a("div",null,[...p[0]||(p[0]=[r("h1",{id:"宝石人",tabindex:"-1"},[d("宝石人 "),r("a",{class:"header-anchor",href:"#宝石人","aria-label":'Permalink to "宝石人"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调011")])])],-1),t('<h1 id="宝石人-1" tabindex="-1">宝石人 <a class="header-anchor" href="#宝石人-1" aria-label="Permalink to &quot;宝石人&quot;">​</a></h1><p>宝石之国-宝石人<br> 魔幻本质<br> 一次性血统<br> 价格：C+1800</p><p>购买这一次性血统后，你会获得宝石人血统的公共特效，接着在分别特效中永久选择一项生效。</p><p>公共特效：</p><p>【宝石人-骨】<br> 放弃韧性槽，将生命槽转化为1倍上限的结构值。<br> 你可以随时在主神空间花费额外B+2000（正常获得属性）将结构值由1倍替换为1.5倍，获得基于天生防御的【防能量】。</p><p>【宝石人-不老】<br> 魂、骨、肉中只有肉继承了衰老的概念。<br> 作为宝石人，你的寿命不会随着时间流逝而自然衰老。</p><p>【宝石人-不死】<br> 即使身体化作沙粒程度的碎片，只要收集齐一定的量用糨糊接回人形就可以继续生存，之后微小生物会自行将裂痕修补好。<br> 需要3个月的时间复活，复活过程中以碎片形式存在，除了观察和移动外无法进行更多的动作，这种形式获得韧性上限值等量的结构值，被摧毁则复活失败。<br> 这是C级别环境来源的复活效果。</p><p>【宝石人-无性】<br> 上半身如少年般纤细、下半身如少女般优美。<br> 宝石人同时视为男性和女性。在确认前置条件时取优，在进行效果处理时取劣。（即，宝石人既可以选择仅限男性的强化，也可以选择仅限女性的强化，且这些强化可以在宝石人身上同时存在，但这不意味着你具有了额外的模版位。但如有些攻击对某种单独的性别有额外效果，这时不论针对男女，宝石人都要承受。如果一个特效对男、女有不同效果，则效果施加方可以选择是何种性别对应的效果生效。）</p><p>分别特效：</p><p>【磷叶石】<br> 硬度3.5，韧性极低。薄荷色。<br> 你在决心相关检定获得2dp士气加值。<br> 你在意志豁免获得4dp士气加值。<br> 每天2次，你在为帮助他人付出行动时，可以选择回复1意志力。</p><p>【辰砂】<br> 硬度2，红色。<br> 你获得黑暗视觉。<br> 每轮一次，你可以标准动作对自身触及范围的全部单位（不分敌我）造成等同你耐力值的毒素点数，对方以强韧豁免。</p><p>【钻石】<br> 硬度10，韧性2级，无色、散发着七彩的光辉。<br> 你获得2天生防御。<br> 你的天生武器伤害值增加3L。<br> 你获得1Dr/钝击。</p><p>【黑钻】<br> 硬度10，韧性特级，黑色。<br> 你获得3天生防御。<br> 你获得1全伤害吸收。</p><p>【金红石】<br> 硬度6，金红双色。<br> 你在医疗相关检定获得3dp技艺加值。<br> 你在手艺相关检定获得3dp技艺加值。<br> 你攻击忽略3部位减值。</p><p>【翡翠】<br> 硬度7，深绿色。<br> 你的社交相关检定获得2dp士气加值。<br> 你的意志豁免获得5dp士气加值。<br> 你获得1Dr/钝击。</p><p>【柱星叶石】<br> 硬度5.5，接近黑色的深紫色。<br> 当你处于夜晚或者阴影环境中，你的潜行获得5dp环境加值。<br> 你的洞察检定获得2dp技艺加值。</p><p>【锆石】<br> 硬度7.5，橙色。<br> 你格挡时获得3格挡防御。<br> 你获得2天生防御。<br> 你获得1Dr/钝击。</p><p>【黑曜石】<br> 硬度5，黑色。<br> 你在器用相关检定获得5dp技艺加值。<br> 你获得1Dr/钝击。</p><p>【黄钻石】<br> 硬度10，黄色。<br> 你获得4先攻加值。<br> 你的移动速度+10。<br> 你获得2天生防御。<br> 你获得2闪避防御。</p><p>【蓝柱石】<br> 硬度7.5，半边是无色，半边是天蓝色。<br> 你在社交相关检定时获得3dp士气减值，他人对你进行察言观色时，会承受3dp表现减值。<br> 你在智力相关检定获得5dp技艺加值。<br> 你获得2洞察防御。</p><p>【变石】<br> 硬度8.5，天蓝色，又称亚历山大石。<br> 你在智力相关检定获得2dp技艺加值。<br> 你的专业：烹饪获得2dp技艺加值。<br> 你获得2天生防御。<br> 在战斗中如果受到大于生命值一半的伤害会变为红色。此时你失去上述所有加值，改为在攻击检定获得6dp士气加值。</p><p>【橄榄石】<br> 硬度6.5，绿色。<br> 你的专业：造纸获得2dp技艺加值。<br> 你的沉着相关检定获得2dp士气加值。<br> 你的意志豁免获得4dp士气加值。<br> 你获得2洞察防御。</p><p>【西瓜碧玺】<br> 硬度7.5，绿色。<br> 你受到近战攻击时会对对方造成1雷电严重伤害。<br> 你的攻击检定获得2dp能量加值，你在进行攻击时可以选择造成雷电伤害。</p><p>【南极石】<br> 硬度3，白色。平时是液体，在温度低时才会变成固体，且温度越低越坚硬。<br> 你在炎热环境下每连续活动10分钟，就需要进行一个强韧豁免，DC为3，失败则承受差值点两倍疲乏点数。环境温度每高于30摄氏度10点，此DC就提升2点。<br> 你无视寒冷环境造成的负面效果。<br> 你在寒冷环境下获得2天生防御与1点全伤害吸收。<br> 环境温度每低于10摄氏度10度，获得的天生防御就额外提升1点。</p><p>【帕德玛刚玉】<br> 你的4米半径内的全部友方获得意志豁免上的4dp士气加值。</p><p>【幽灵水晶与黑水晶】<br> 硬度7。二层构造，外层是白色的幽灵水晶，内层是黑色的黑水晶。<br> 你可以移动动作切换你的宝石颜色为白色或者黑色。<br> 当宝石颜色为黑色时，你的潜行获得4dp环境加值。<br> 当宝石颜色为白色时，你的社交检定获得4dp士气加值。</p><p>【青金岩】<br> 硬度5，深蓝色。复合体质，由青金石、黄铁矿、蓝方石、方钠石、玻璃为中心的六种矿物所构成。<br> 你的学识相关检定获得6dp技艺加值。</p><p>【金绿宝石】<br> 硬度8.5，蜂蜜色。<br> 你获得2天生防御。<br> 你的智力相关检定获得2dp技艺加值。<br> 你的社交相关检定获得2dp士气加值。<br> 你的沉着相关检定获得2dp士气加值。</p><p>【红钻石】<br> 红色。第一位出生的宝石。<br> 你获得快速维修2（医疗点36）。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',31)])])}const m=b(n,[["render",s]]);export{f as __pageData,m as default};
